{"type":"freeform","cover":{"titleText":"","subTitleText":"","presenterText":"","dateText":"","logos":[]},"section":{"sectionText":"","smallerSectionText":""},"freeform":{"content":[[{"type":"text","stretch":true,"fillArea":true,"textSize":1,"textBackground":"grey","placeholderInvisible":false,"useFigureAdditionalScale":false,"figureAdditionalScale":1,"span":4,"markdown":"BCG: Sustained disruptions through 2024, with volumes dipping below expectations with an average disruption of ~14% from May to December 2024, but steady recovery into mid-2025 with sustained periods of surplus followed by one small dip in August 2025 of 12%.

